create table dirkspzm32.ems_belege (
    sid              varchar2(2 char) default '01' not null enable,
    firma_nr         number default 1 not null enable,
    ems_beleg_nr     varchar2(20 char) not null enable,
    erz_login_id     number(*, 0) not null enable,
    erz_datum        date not null enable,
    aend_login_id    number(*, 0),
    aend_datum       date,
    ems_beleg_typ    varchar2(10 char) default 'L' not null enable,
    beleg_nr_ext     varchar2(50 char),
    beleg_nr_ext2    varchar2(50 char),
    beleg_nr_fracht  varchar2(50 char),
    beleg_datum_zeit date not null enable,
    beleg_notiz      varchar2(255 char),
    b_ems_konto_nr   number(*, 5) not null enable,
    b_adress_id      number(*, 0) not null enable,
    gb_ems_konto_nr  number(*, 5),
    gb_adress_id     number(*, 0),
    gb_ems_beleg_nr  number(*, 5),
    t_adress_id      number(*, 0),
    t_fahrzeug       varchar2(20 char),
    ldst_adress_id   number(*, 0),
    pruef_login_id   number(*, 0),
    pruef_datum      date,
    storno_login_id  number(*, 0),
    storno_datum     date,
    k_adress_id      number(*, 0),
    vorgang_id       number(*, 0)
);

alter table dirkspzm32.ems_belege
    add constraint pk_ems_belege primary key ( ems_beleg_nr )
        using index enable;


